from typing import List

class Solution:
    def solve(self, n: int) -> List[List[int]]:
        def backtrack(row: List[int], col: List[int], curr: int):
            if curr == n:
                res.append(row[:])
                return

            for j in range(n):
                if col[j] == 0 and row[j] == 0:
                    col[j] = 1
                    row[j] = 1
                    backtrack(row, col, curr + 1)
                    col[j] = 0
                    row[j] = 0

        res = []
        backtrack([0] * n, [0] * n, 0)
        return res

